INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9621fb9-a5df-579d-b8ba-cb2177113e90', '1aa3ffb6-7528-5067-a6ec-ac602fb9667c', 'ربطٌ صحيحٌ بين الحاسّة وعضوها هو…', '[{"id":"a","text":"الذوق ← العين"},{"id":"b","text":"السمع ← الأذن"},{"id":"c","text":"الإبصار ← الأنف"},{"id":"d","text":"الشمّ ← اللسان"}]'::jsonb, 'b', 'السمع حاسّةٌ عضوها الأذن. أمّا البقيّة فخاطئة: الذوق للسان، والإبصار للعين، والشمّ للأنف.', 1)
