  ('31ac0215-e96b-5828-8256-6e821774c510', 'e9ba5ab5-4cab-5db9-a35f-0c147e5b7001', 'من أعراض مرض الزكام…', '[{"id":"a","text":"سيلان الأنف والعطس"},{"id":"b","text":"تحسّن السمع"},{"id":"c","text":"وضوح الإبصار"},{"id":"d","text":"قوّة في الأظافر"}]'::jsonb, 'a', 'الزكام يسبّب سيلان الأنف والعطس، وهو مرضٌ ينتقل بين الناس.', 5)
