INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45dfd7e6-4539-5689-b228-d31694c47d6f', 'e9ba5ab5-4cab-5db9-a35f-0c147e5b7001', 'لكي لا تُتعب عينيك أمام الشاشة، ماذا تفعل؟', '[{"id":"a","text":"ألصق وجهي بالشاشة"},{"id":"b","text":"أُطفئ كلّ الأنوار"},{"id":"c","text":"لا أبتعد ولا أرتاح أبدًا"},{"id":"d","text":"أبتعد مسافةً كافيةً وأرتاح بين الحين والآخر"}]'::jsonb, 'd', 'الاقتراب الشديد والظلام يُتعبان العين، فنبتعد مسافةً كافيةً ونريح العين لنحمي الإبصار.', 6)
