INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f69af201-8f16-5e76-9842-5e3db7287ac2', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'أردتَ أن تعرف هل الفاكهة ناضجةٌ دون أن تأكلها. أيّ حاسّتين تساعدانك أكثر؟', '[{"id":"a","text":"السمع والذوق"},{"id":"b","text":"السمع فقط"},{"id":"c","text":"الذوق فقط"},{"id":"d","text":"الإبصار والشمّ"}]'::jsonb, 'd', 'دون أكلٍ نستعمل العين (اللون) والأنف (الرائحة): الإبصار والشمّ. الذوق يحتاج إلى الأكل، والسمع لا يفيد هنا.', 1)
