INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a7796ef-ca1b-52b5-a3b6-3ada093fa7cc', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'شخصٌ سُدّ أنفه بالزكام فلم يعد يُحسّ بنكهة الطعام جيّدًا. ماذا نستنتج؟', '[{"id":"a","text":"حاسّة الشمّ تساعد على إدراك نكهة الطعام"},{"id":"b","text":"اللسان توقّف عن العمل نهائيًّا"},{"id":"c","text":"الزكام يقوّي حاسّة الذوق"},{"id":"d","text":"النكهة لا علاقة لها بالأنف"}]'::jsonb, 'a', 'الخطأ الشائع: الظنّ أنّ الطعم من اللسان وحده. الأنف (الشمّ) يساعد كثيرًا على إدراك النكهة، فإذا سُدّ ضعف الإحساس بها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('525abcae-c1db-5b63-9825-aca9fa95e28b', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'مجموعةٌ كلّها أعضاء حسٍّ صحيحة هي…', '[{"id":"a","text":"العين، اليد، القدم"},{"id":"b","text":"الأذن، المعدة، الرئة"},{"id":"c","text":"العين، الأذن، الأنف، اللسان، الجلد"},{"id":"d","text":"القلب، العين، الأذن"}]'::jsonb, 'c', 'أعضاء الحسّ الخمسة هي العين والأذن والأنف واللسان والجلد. المعدة والرئة والقلب ليست أعضاء حسّ.', 3)
