INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db309177-871c-547e-b446-4958c55b93d5', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'في مكتبةٍ هادئة، الإضاءة ضعيفةٌ جدًّا. أيّ نصيحةٍ صحيحةٌ لحماية بصرك؟', '[{"id":"a","text":"أُقرّب الكتاب جدًّا من عينيّ"},{"id":"b","text":"أقرأ في الظلام لأريح عينيّ"},{"id":"c","text":"أنظر إلى مصباحٍ قويٍّ مباشرة"},{"id":"d","text":"أزيد الإضاءة لتصبح كافيةً قبل القراءة"}]'::jsonb, 'd', 'الخطأ الشائع: القراءة في ضوءٍ ضعيف أو تقريب الكتاب. الصحيح أن نوفّر ضوءًا كافيًا، فذلك يحمي الإبصار.', 4)
