  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cda5cbfc-9c1a-5362-9b28-0320544f8878', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'زميلك مزكومٌ ويعطس قربك. ما التصرّف الأسلم للجميع؟', '[{"id":"a","text":"أستعمل منديله أنا أيضًا"},{"id":"b","text":"أقترب منه أكثر"},{"id":"c","text":"يغطّي أنفه وفمه عند العطس ونغسل أيدينا"},{"id":"d","text":"نتجاهل الأمر لأنّ الزكام لا ينتقل"}]'::jsonb, 'c', 'الزكام ينتقل بين الناس، فالأسلم أن يغطّي العاطس أنفه وفمه وأن نغسل أيدينا لنمنع العدوى.', 5)
