INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd301ebe-eb9a-5338-ad62-57f391319cd2', 'b79881eb-2208-55b7-b2ea-2336113cebc5', 'أيّ جملةٍ تُفرّق بدقّةٍ بين الحاسّة والعضو؟', '[{"id":"a","text":"السمع عضوٌ والأذن حاسّة"},{"id":"b","text":"السمع حاسّةٌ والأذن عضوٌ يقوم بها"},{"id":"c","text":"الأذن والسمع شيءٌ واحد"},{"id":"d","text":"العين حاسّةٌ والإبصار عضو"}]'::jsonb, 'b', 'الخطأ الشائع: الخلط بين الحاسّة والعضو. السمع حاسّةٌ، والأذن هي العضو الذي يقوم بها؛ وكذلك الإبصار حاسّةٌ والعين عضوها.', 6)
