  ('43dc463e-a3d5-5ba6-9ed8-45b2e763755c', '77a08adc-9949-516c-872e-a660f0fe6e34', 'بأيّ حاسّةٍ نعرف أنّ الموسيقى تُعزف في الغرفة المجاورة؟', '[{"id":"a","text":"السمع"},{"id":"b","text":"الذوق"},{"id":"c","text":"اللمس"},{"id":"d","text":"الإبصار"}]'::jsonb, 'a', 'نُدرك الأصوات بحاسّة السمع وعضوها الأذن، فنعرف أنّ هناك موسيقى تُعزف.', 1)
