INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b030a877-4ac0-54bd-9780-a503495aab3e', '2d6867d0-27bf-5445-81e0-9dde751cb6f6', 'قال طفل: «طالما أغسل أسناني فلا يضرّني الإكثار من الحلويات». ما الأصحّ؟', '[{"id":"a","text":"صحيح تمامًا، الحلويات بلا ضرر"},{"id":"b","text":"الإكثار من الحلويات يزيد خطر التسوّس، فنقلّل منها أيضًا"},{"id":"c","text":"الحلويات تقوّي السنّ دائمًا"},{"id":"d","text":"غسل الأسنان غير مفيد"}]'::jsonb, 'b', 'الخطأ الشائع: الاكتفاء بالغسل. الوقاية تكون بالغسل وأيضًا بالتقليل من الحلويات لأنّها تزيد خطر التسوّس.', 4)
