  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6f37671-a0e3-5852-b545-6c55afc4a753', '2d6867d0-27bf-5445-81e0-9dde751cb6f6', 'أيّ سلسلةٍ تصف رحلة قطعة جزرٍ في جسم الأرنب بالترتيب الصحيح؟', '[{"id":"a","text":"الدم ← الفم ← المعدة"},{"id":"b","text":"الأمعاء ← المعدة ← الفم"},{"id":"c","text":"المعدة ← الأمعاء ← الفم"},{"id":"d","text":"الفم ← المعدة ← الأمعاء ← الدم"}]'::jsonb, 'd', 'تُمضغ الجزرة في الفم، ثمّ تنزل إلى المعدة فالأمعاء حيث تُمتصّ مغذّياتها إلى الدم. هذا هو الترتيب الكامل.', 5)
