  ('060e79f7-9653-5511-8884-9c8cb94b3d86', 'dea58bc8-2279-5b84-acdf-fbbe11cd0481', 'انظر إلى هذا الحيوان. كيف يتنقّل؟ <svg viewBox="0 0 120 80" xmlns="http://www.w3.org/2000/svg"><path d="M30 40 q26 -22 56 0 q-26 22 -56 0 z" fill="#38bdf8" stroke="#1f2937" stroke-width="3" stroke-linejoin="round"/><path d="M30 40 l-16 -12 l0 24 z" fill="#0ea5e9" stroke="#1f2937" stroke-width="3" stroke-linejoin="round"/><circle cx="78" cy="36" r="3" fill="#1f2937"/><line x1="8" y1="68" x2="112" y2="68" stroke="#0ea5e9" stroke-width="3" stroke-dasharray="6 5"/></svg>', '[{"id":"a","text":"بالسباحة بحرا"},{"id":"b","text":"بالطيران جوّا"},{"id":"c","text":"بالزحف برّا"},{"id":"d","text":"بالقفز برّا"}]'::jsonb, 'a', 'الصورة سمكة لها ذيلٌ وتعيش في الماء، فهي تتنقّل بالسباحة بحرا.', 6)
