INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d68d11f-ca98-5f99-a84d-23d4fbab183f', '710e860e-af4f-5774-bd22-c22db5a687f8', 'أيّ مجموعةٍ كلّها حيوانات تتنقّل برّا؟', '[{"id":"a","text":"السمكة، العصفور، الحمامة"},{"id":"b","text":"الحصان، الأرنب، الثعبان"},{"id":"c","text":"السمكة، العصفور، الأرنب"},{"id":"d","text":"الحمامة، السمكة، الثعبان"}]'::jsonb, 'b', 'الحصان والأرنب والثعبان كلّها حيوانات برّيّة. أمّا السمكة فبحرا والعصفور والحمامة فجوّا.', 2)
