INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c621695-51e7-5d3b-815c-e601f5bcd59f', '710e860e-af4f-5774-bd22-c22db5a687f8', 'قال طفل: «الجناح والزعنفة عضوان لهما الوظيفة نفسها». ما الصحيح؟', '[{"id":"a","text":"صحيح، كلاهما للطيران"},{"id":"b","text":"صحيح، كلاهما للسباحة"},{"id":"c","text":"خطأ، الجناح للطيران والزعنفة للسباحة"},{"id":"d","text":"خطأ، كلاهما للمشي"}]'::jsonb, 'c', 'الخطأ الشائع: الخلط بين الأعضاء. الجناح يتكيّف مع الطيران جوّا، والزعنفة مع السباحة بحرا.', 4)
