INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('303a115a-3b3b-5f4c-9c2b-86ea75e65c47', 'b3873835-7068-5165-b9b0-e80a30536986', 'حيوانٌ جسمه أملس وله زعانف وذيلٌ ولا أطراف له. أين يتنقّل وكيف؟', '[{"id":"a","text":"جوّا بالطيران"},{"id":"b","text":"برّا بالقفز"},{"id":"c","text":"برّا بالزحف"},{"id":"d","text":"بحرا بالسباحة"}]'::jsonb, 'd', 'الزعانف والذيل والجسم الأملس أعضاءٌ متكيّفةٌ مع الماء، فالحيوان يتنقّل بحرا بالسباحة، مثل السمكة.', 1)
