INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b213298-2b87-5a71-8c57-83c1534dd863', '641201a3-9ac7-5589-a32b-2660eda15bc2', 'أمامك: خروف، سمكة، كلب، إنسان. كم منها يتنفّس بالرئتين؟', '[{"id":"a","text":"واحد فقط"},{"id":"b","text":"ثلاثة: الخروف والكلب والإنسان"},{"id":"c","text":"كلّها"},{"id":"d","text":"ولا واحد"}]'::jsonb, 'b', 'الخروف والكلب والإنسان حيواناتٌ برّيّة تتنفّس بالرئتين. السمكة وحدها تتنفّس بالغلاصم. فالعدد ثلاثة.', 2)
