INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0416037-bbdd-55cf-b0a6-2167a74226dc', '94e5e778-44a0-51d3-9fb6-387dfe5e2be6', 'أراد بستانيٌّ أن يحصل على شجرة وردٍ تشبه تمامًا شجرته الجميلة. أيّ طريقةٍ أنسب؟', '[{"id":"a","text":"أخذ عقلةٍ من الشجرة وغرسها (تكاثر دون بذور)"},{"id":"b","text":"تركها دون فعل شيء"},{"id":"c","text":"إحضار سمكةٍ من الماء"},{"id":"d","text":"حرق الشجرة"}]'::jsonb, 'a', 'العقلة تُعطي نباتًا يشبه النبات الأمّ، فالتكاثر دون بذور أنسب للحصول على وردٍ مماثل.', 1)
