  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d25e674-a416-541c-9ecf-a8fde8046369', '72e34118-edb9-5321-96d5-1f954002f7b9', 'لماذا تُصنع مقابض الأواني غالبًا من الخشب أو البلاستيك؟', '[{"id":"a","text":"لأنّها عازلة فلا تنقل حرارة الإناء إلى اليد"},{"id":"b","text":"لأنّها ناقلة فتسخن بسرعة"},{"id":"c","text":"لأنّها أجمل فقط"},{"id":"d","text":"لأنّها أثقل"}]'::jsonb, 'a', 'الخشب والبلاستيك عازلان للحرارة، فالمقبض لا ينقل حرارة الإناء إلى اليد فلا تحترق.', 2)
