  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('134f43a5-2530-5ab8-adb4-0817a6f67d5f', '72e34118-edb9-5321-96d5-1f954002f7b9', 'قال طفل: «اللمس يكفي لمعرفة درجة الحرارة بالضبط». ما الصحيح؟', '[{"id":"a","text":"صحيح، اللمس دقيقٌ تمامًا"},{"id":"b","text":"خطأ، اللمس تقريبيّ والمحرار هو الدقيق"},{"id":"c","text":"اللمس يقيس الطول"},{"id":"d","text":"اللمس لا علاقة له بالحرارة"}]'::jsonb, 'b', 'الخطأ الشائع: الاعتماد على اللمس لقياسٍ دقيق. اللمس تقريبيّ فقط (حارّ/بارد)، والمحرار يعطي القياس الدقيق.', 3)
