  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a985f536-6908-519d-a855-ec0c859192ba', '72e34118-edb9-5321-96d5-1f954002f7b9', 'قضيب معدنٍ سُخّن فطال قليلًا. ماذا نسمّي هذه الظاهرة؟', '[{"id":"a","text":"التقلّص"},{"id":"b","text":"التجمّد"},{"id":"c","text":"التمدّد"},{"id":"d","text":"الذوبان"}]'::jsonb, 'c', 'عند التسخين يطول المعدن قليلًا، وهذه الظاهرة هي التمدّد.', 4)
