INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c88e3d7-9ea2-5a3f-aebd-3596121164b8', '72e34118-edb9-5321-96d5-1f954002f7b9', 'أيّ ترتيبٍ صحيحٌ من الأبرد إلى الأسخن؟', '[{"id":"a","text":"ماء الشاي، ماء عادي، ماء الثلّاجة"},{"id":"b","text":"ماء عادي، ماء الشاي، ماء الثلّاجة"},{"id":"c","text":"ماء الثلّاجة، ماء عادي، ماء الشاي"},{"id":"d","text":"ماء الشاي، ماء الثلّاجة، ماء عادي"}]'::jsonb, 'c', 'الأبرد ماء الثلّاجة، ثمّ الماء العادي، ثمّ الأسخن ماء الشاي. فالترتيب الصحيح من الأبرد إلى الأسخن هو: الثلّاجة، عادي، الشاي.', 5)
